// Утиліти для роботи з авторизацією та токеном

const TOKEN_KEY = 'auth_token';

// Зберегти токен у localStorage
export const saveToken = (token: string) => {
  if (typeof window !== 'undefined') {
    localStorage.setItem(TOKEN_KEY, token);
  }
};

// Отримати токен з localStorage
export const getToken = (): string | null => {
  if (typeof window !== 'undefined') {
    return localStorage.getItem(TOKEN_KEY);
  }
  return null;
};

// Видалити токен (logout)
export const removeToken = () => {
  if (typeof window !== 'undefined') {
    localStorage.removeItem(TOKEN_KEY);
  }
};

// Перевірити, чи користувач авторизований
export const isAuthenticated = (): boolean => {
  return !!getToken();
};

// Отримати заголовки з токеном для fetch запитів
export const getAuthHeaders = () => {
  const token = getToken();
  return {
    'Content-Type': 'application/json',
    ...(token && { 'Authorization': `Bearer ${token}` }),
  };
};
