"use client"

import Image from "next/image"
import { useState, useEffect } from "react"
import { ProdactCard } from "../components/ProdactCard"
import { mockProducts } from "../services/mockData"
import styles from "./page.module.css"
import { useCartStore } from "../store/cartStore"
import { isAuthenticated, removeToken } from "../utils/auth"
import { useRouter } from "next/navigation"

export default function Home() {
    const router = useRouter();
    const [currentProduct, setCurrentProduct] = useState(0)
    const [authenticated, setAuthenticated] = useState(false);

    useEffect(() => {
        setAuthenticated(isAuthenticated());
    }, []);

    const handleLogout = () => {
        removeToken();
        setAuthenticated(false);
        alert('Ви вийшли з системи');
    };

    const handleLogin = () => {
        router.push('/login');
    };

    const handlePrev = () => {
        setCurrentProduct(prev => prev === 0 ? mockProducts.length - 1 : prev - 1)
    }

    const handleNext = () => {
        setCurrentProduct(prev => prev === mockProducts.length - 1 ? 0 : prev + 1)
    }
    const getVisibleProducts = () => {
        const products = [];
        for (let i = 0; i < 3; i++) {
            products.push(mockProducts[(currentProduct + i) % mockProducts.length]);
        }
        return products;
    };

    const items = useCartStore((state) => state.items);

    return (

        <div className={styles.container}>

            <header className={styles.header}>
                <Image src="/images/logo.jpg" alt="Logo" width={180} height={90} className={styles.logo}></Image>
                <h1 className={styles.title}>ТОВАР <span className={styles.by}>by</span> CREATOR IT ACADEMY</h1>
                <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                    {authenticated ? (
                        <button onClick={handleLogout} style={{ 
                            padding: '10px 20px', 
                            backgroundColor: '#ff4444', 
                            color: 'white', 
                            border: 'none', 
                            borderRadius: '5px',
                            cursor: 'pointer',
                            fontSize: '14px'
                        }}>
                            Вийти
                        </button>
                    ) : (
                        <button onClick={handleLogin} style={{ 
                            padding: '10px 20px', 
                            backgroundColor: '#4CAF50', 
                            color: 'white', 
                            border: 'none', 
                            borderRadius: '5px',
                            cursor: 'pointer',
                            fontSize: '14px'
                        }}>
                            Увійти
                        </button>
                    )}
                    <a href="/basket" className={styles.basketLink}>
                        <button className={styles.basketButton}>
                            <Image src="/images/basket.png" alt="Basket" width={40} height={40} className={styles.basketImage}>
                            </Image>
                            <span className={styles.basketCount}>{items.reduce((sum, item) => sum + item.quantity, 0)}</span>
                        </button>
                    </a>
                </div>
            </header>


            <main className={styles.main}>

                <button onClick={handlePrev} className={styles.arrowButton}>
                    <img src="/images/left.png" alt="Назад" className={styles.arrowIcon} />
                </button>


                <div className={styles.productsGrid}>
                    {getVisibleProducts().map((product) => (
                        <ProdactCard key={product.id} data={product} />
                    ))}
                </div>
                <button onClick={handleNext} className={styles.arrowButton}>
                    <img src="/images/right.png" alt="вперед" className={styles.arrowIcon} />
                </button>

            </main>
            <footer>


            </footer>

        </div>


    )
}